var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이전에 본 적 있는 로켓탄입니다. 마젤란 예언회로군요.","JPN":"以前見たことがあるロケット弾です。マジェラン預言会ですね。","ENG":"I've seen this rocket before. It must be from the Magellan Prediction Society.","TWN":"我有看過這個砲彈，是麥哲倫預言會的。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"공명파 발생기를 숨겨 둔 것도 역시 저 녀석들이었나?","JPN":"共鳴波発生器を隠しておいたのも、やはりあいつらだったのか？","ENG":"Do you think the MPS planted the pulse generator too?","TWN":"共鳴裝置也是那些傢伙藏的吧？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"하지만 지하철에 처박혀 사는 시궁쥐들이 어느 구멍으로 그런 물건을…….","JPN":"しかし地下鉄に引きこもって暮らすドブネズミどもがどうしてそんな物を……","ENG":"But those sewer rats literally live underground… How did they manage to score something like that?","TWN":"不過，躲在地鐵裡的過街老鼠，怎麼會有這種東西……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"종교인을 후원하는 사례는 흔하죠. 면세 수단으로도 유용합니다.","JPN":"宗教を後援するケースはよくあります。免税の手段としても便利です。","ENG":"It's not rare for religious organizations to secure affluent sponsors. The tax exemptions are particularly attractive.","TWN":"贊助宗教人士很普遍，而且還可以扣稅。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"핸들 꽉 잡아! 지금 사고 내면 다 죽는다!","JPN":"ハンドルをしっかり握れ！　今事故ったら全員死ぬぞ！","ENG":"You'd better grab that wheel tight! You'll kill us all if we crash now!","TWN":"握緊方向盤！萬一出車禍會死人的！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"걱정 마세요, 교관님! 무면허지만 사고는 살면서 한 번도 안 냈습니다!","JPN":"心配しないでください、教官！　無免許ですけど事故ったことは一度もありません！","ENG":"Don’t you worry, Instructor! I never got a driver's license, but I've never got into an accident either!","TWN":"別擔心，教官！雖然我沒有駕照，但從出生到現在，我可是從沒出過車禍呢！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……자리 바꿔! 지금 당장!","JPN":"……俺と代われ！　今すぐ！","ENG":"…We're switching seats! Now!","TWN":"……現在立刻換位置！馬上！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"HERETIC_NPC_NULL_A","text":{"KOREA":"우리는 마젤란의 형제들! 신세계에서 살아갈 예언의 신인류다!","JPN":"我々はマジェランの兄弟！　新世界で生きていく預言の新人類である！","ENG":"We're the brethren of Magellan, chosen by the Prophecy... ‘Tis the New World we shall dwell in, for we’re the New Humanity...","TWN":"麥哲倫預言會的弟兄們！預言活在新世界的新人類！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HERETIC_NPC_NULL_B","text":{"KOREA":"놈들이 궁지에 몰렸다! 저들의 피를 예언자님께 바쳐라!","JPN":"やつらが窮地に追い込まれた！　やつらの血を預言者様に捧げろ！","ENG":"We've got them cornered! We shall offer their blood as a sacrifice unto the Prophet!","TWN":"他們走投無路了！把他們的血獻給預言家吧！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이전에 마주쳤을 때보다 언동이 더 과격해졌군요.","JPN":"以前会った時よりも言動がさらに過激になりましたね。","ENG":"They've grown even more fanatical than our previous encounter.","TWN":"言行比之前交手時更瘋狂呢。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"관찰 결과, 맥박 및 안구 운동 횟수가 정상치보다 70% 가량 높습니다.","JPN":"観察の結果、脈拍および眼球の運動回数が正常値より70％ほど高いです。","ENG":"Based on my observations, their heart rate and eye movements exceed the average by approximately 70%.","TWN":"觀察結果，脈搏和眼球轉動次數，比正常值高出約70%。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"다른 팀에서 총을 쏴 맞춰도 꿈쩍 안 했다던데, 설마 약이라도 먹인 걸까요?","JPN":"他のチームが銃を撃ってもびくともしなかったそうですが、まさか薬物でも使ったのでしょうか？","ENG":"The fellas in the other squad said those maniacs didn't even budge when they got shot. Could they be high on something?","TWN":"聽說其他隊的人說，就算被子彈打到也不為所動，難道是被餵食毒品嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"저 맛이 간 상태를 보면 그렇겠지. 이름만 종교 단체지 약장수들과 다를 게 없군.","JPN":"あの状態を見る限りそうだろうな。名前だけの宗教団体でシャブの売人と変わらないな。","ENG":"They sure look like it. For all their claims of being a religious organization, they're nothing but a bunch of drug dealers now.","TWN":"看他們那副德性應該是吧。只有名字像宗教團體，實際上和藥頭沒兩樣。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"교, 교관님! 후미의 차가 전복되었습니다!","JPN":"教官！　後ろの車が横転しました！","ENG":"S-sir! The vehicle behind us just flipped over!","TWN":"教…教官！後方的車翻覆了！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L36_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"뭐야? 제길……!","JPN":"何だと？　くそっ……！","ENG":"What? Damn it…!","TWN":"什麼？該死……！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L37_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"다른 친구들한테 장비 챙기라고 해! 낙오된 녀석들을 구출한다!","JPN":"他のチームに連絡して装備を用意するように伝えろ！　取り残された団員を救出する！","ENG":"Tell everyone else to gear up! We're going to extract the stragglers!","TWN":"叫其他人拿好裝備！我們要救回那些脫隊的人！"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저한테 가진 걸 버릴 각오를 하라더니 말과 행동이 따로 노는군요. 휴먼.","JPN":"私には持っているものを捨てる覚悟をしろと言ったのに、言葉と行動が伴っていないですね、ヒューマン。","ENG":"So much for forfeiting everything like you said, human.","TWN":"還跟我說必須捨棄所擁有的，結果根本言行不一嘛，人類。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"미안하군. 오늘은 분리수거 날이 아니라 더 오래 가지고 있어야겠어.","JPN":"すまんな。今日はゴミ収集日じゃないから、もうしばらくは持っておかないと。","ENG":"Sorry. I'm going to have to hold onto you a bit longer since the recycling truck's not coming today.","TWN":"抱歉，今天不太適合斷捨離，我想要繼續擁有他們。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"이럴 것 같아서 젊은 녀석들하고 더 안 엮이려 했는데……. 불평하기엔 너무 늦었군.","JPN":"これだから若いやつらとは絡まないようにしていたのに……文句を言うには遅いか。","ENG":"This is exactly why I didn't want to get involved with youngsters again… I guess it's too late to complain.","TWN":"我就怕會這樣，所以才不想再和年輕人混在一起……不過現在抱怨這些也沒什麼用。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_UPROAR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};